-- Enable RLS on every public table that was exposed without protection.
-- The service_role key bypasses RLS automatically, so backend continues
-- to work. Anon/public access is now blocked on all tables.

ALTER TABLE public.omega_events                        ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.downloads_manifest                  ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.study_materials                     ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.marginalia                          ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.omega_kinetic_memory                ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.omega_idempotency                   ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.omega_state                         ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.omega_recipe_registry               ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.magnus_signal_states                ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.aeon_runs                           ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.omega_namespace_config              ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.omega_provider_metrics              ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.omega_forge_jobs                    ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.learning_experiments                ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.system_improvements                 ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.learning_progress                   ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.experimental_recipes                ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.omega_state_legacy_20260305202254   ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.omega_memory                        ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.omega_task_graph                    ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.omega_sub_tasks                     ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.omega_provider_state                ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.omega_memory_entries                ENABLE ROW LEVEL SECURITY;

-- Install pg_cron for scheduled maintenance
CREATE EXTENSION IF NOT EXISTS pg_cron;

-- Retention: omega_provider_metrics — keep 30 days
-- This table had 15,497 rows and grows with every API call.
SELECT cron.schedule(
  'purge_provider_metrics_30d',
  '0 3 * * *',  -- daily at 3am UTC
  $$DELETE FROM public.omega_provider_metrics WHERE ts < now() - interval '30 days'$$
);

-- Retention: omega_events — keep 90 days
-- This is the event chain (has hashes), so we keep more history.
SELECT cron.schedule(
  'purge_omega_events_90d',
  '0 3 * * *',  -- daily at 3am UTC
  $$DELETE FROM public.omega_events WHERE ts < now() - interval '90 days'$$
);

-- Retention: omega_memory — keep 180 days (embeddings are expensive, worth keeping longer)
SELECT cron.schedule(
  'purge_omega_memory_180d',
  '0 4 * * *',  -- daily at 4am UTC
  $$DELETE FROM public.omega_memory WHERE ts < now() - interval '180 days'$$
);

-- This table is empty and was clearly created as a backup snapshot on 2026-03-05.
-- It serves no ongoing purpose and exposes schema unnecessarily.
DROP TABLE IF EXISTS public.omega_state_legacy_20260305202254;

